{"code":"import json
import re

books_path = locals()['var_function-call-7229594273416415337']
reviews_path = locals()['var_function-call-18367235769688117238']

with open(books_path, 'r') as f:
    books = json.load(f)
with open(reviews_path, 'r') as f:
    reviews = json.load(f)

def get_id(s):
    if not isinstance(s, str): return None
    m = re.search(r'(\d+)$', s)
    if m:
        return int(m.group(1))
    return None

book_ids = set()
for b in books:
    bid = get_id(b.get('book_id'))
    if bid is not None:
        book_ids.add(bid)

review_ids = set()
for r in reviews:
    pid = get_id(r.get('purchase_id'))
    if pid is not None:
        review_ids.add(pid)

print("__RESULT__:")
print(json.dumps({
    "book_ids_sample": list(book_ids)[:10],
    "review_ids_sample": list(review_ids)[:10],
    "intersection_count": len(book_ids.intersection(review_ids)),
    "book_count": len(book_ids),
    "review_count": len(review_ids)
}))
"}

